#include <bits/stdc++.h>
using namespace std;
const int INF=(1LL<<31-1);
int n,m,q;
vector<int> g[1003];
int bfs(int x,int y){
    int sum=1,dist[1003];
    queue<int> q;
    q.push(x);
    for(int i=1;i<=n;i++)
        dist[i]=INF;
    dist[x]=0;
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop();
        if(dist[f]==y)
            break;
        for(int i=0;i<len;i++)
            if(dist[g[f][i]]==INF)
                sum++,dist[g[f][i]]=dist[f]+1,q.push(g[f][i]);
    }
    return sum;
}
int main(){
    int ans=0;
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=m;i++){
        int a,b;
        scanf("%d%d",&a,&b);
        g[a].push_back(b);
        g[b].push_back(a);
    }
    for(int i=1;i<=q;i++){
        int a,b;
        scanf("%d%d",&a,&b);
        ans+=bfs(a,b);
    }
    printf("%.2lf",1.0*ans/q);
    return 0;
}
